import{_ as s,o as a,c as i,a2 as e}from"./chunks/framework.CGYl2SZ_.js";const t=JSON.parse('{"title":"timezone","description":"timezone 页面","frontmatter":{"title":"timezone","description":"timezone 页面"},"headers":[],"relativePath":"concepts/timezone.md","filePath":"concepts/timezone.md"}');const n=s({name:"concepts/timezone.md"},[["render",function(s,t,n,l,o,p){return a(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="时区" tabindex="-1">时区 <a class="header-anchor" href="#时区" aria-label="Permalink to &quot;时区&quot;">​</a></h1><h1 id="时区-1" tabindex="-1">时区 <a class="header-anchor" href="#时区-1" aria-label="Permalink to &quot;时区&quot;">​</a></h1><p>OpenClaw 标准化时间戳，以便模型看到<strong>单个参考时间</strong>。</p><h2 id="消息信封-默认本地" tabindex="-1">消息信封（默认本地） <a class="header-anchor" href="#消息信封-默认本地" aria-label="Permalink to &quot;消息信封（默认本地）&quot;">​</a></h2><p>入站消息包装在如下信封中：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Provider ... 2026-01-05 16:26 PST] message text</span></span></code></pre></div><p>信封中的时间戳<strong>默认是主机本地</strong>，精确到分钟。</p><p>您可以覆盖此设置：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      envelopeTimezone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;local&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;utc&quot; | &quot;local&quot; | &quot;user&quot; | IANA 时区</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      envelopeTimestamp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;on&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;on&quot; | &quot;off&quot;</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      envelopeElapsed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;on&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;on&quot; | &quot;off&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><code>envelopeTimezone: &quot;utc&quot;</code> 使用 UTC。</li><li><code>envelopeTimezone: &quot;user&quot;</code> 使用 <code>agents.defaults.userTimezone</code>（回退到主机时区）。</li><li>使用明确的 IANA 时区（例如 <code>&quot;Europe/Vienna&quot;</code>）以获得固定偏移。</li><li><code>envelopeTimestamp: &quot;off&quot;</code> 从信封头中移除绝对时间戳。</li><li><code>envelopeElapsed: &quot;off&quot;</code> 移除经过时间后缀（<code>+2m</code> 样式）。</li></ul><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p><strong>本地（默认）：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Signal Alice +1555 2026-01-18 00:19 PST] hello</span></span></code></pre></div><p><strong>固定时区：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Signal Alice +1555 2026-01-18 06:19 GMT+1] hello</span></span></code></pre></div><p><strong>经过时间：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Signal Alice +1555 +2m 2026-01-18T05:19Z] follow-up</span></span></code></pre></div><h2 id="工具负载-原始提供商数据-规范化字段" tabindex="-1">工具负载（原始提供商数据 + 规范化字段） <a class="header-anchor" href="#工具负载-原始提供商数据-规范化字段" aria-label="Permalink to &quot;工具负载（原始提供商数据 + 规范化字段）&quot;">​</a></h2><p>工具调用（<code>channels.discord.readMessages</code>、<code>channels.slack.readMessages</code> 等）返回<strong>原始提供商时间戳</strong>。 我们还附加了规范化字段以保持一致：</p><ul><li><code>timestampMs</code>（UTC 纪元毫秒）</li><li><code>timestampUtc</code>（ISO 8601 UTC 字符串）</li></ul><p>保留原始提供商字段。</p><h2 id="系统提示的用户时区" tabindex="-1">系统提示的用户时区 <a class="header-anchor" href="#系统提示的用户时区" aria-label="Permalink to &quot;系统提示的用户时区&quot;">​</a></h2><p>设置 <code>agents.defaults.userTimezone</code> 以告诉模型用户的本地时区。如果未设置，OpenClaw 在运行时解析<strong>主机时区</strong>（无配置写入）。</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">userTimezone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;America/Chicago&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>系统提示包括：</p><ul><li><code>Current Date &amp; Time</code> 部分，包含本地时间和时区</li><li><code>Time format: 12-hour</code> 或 <code>24-hour</code></li></ul><p>您可以使用 <code>agents.defaults.timeFormat</code>（<code>auto</code> | <code>12</code> | <code>24</code>）控制提示格式。</p><p>参见<a href="/date-time.html">日期和时间</a>了解完整行为和示例。</p>',28)])])}]]);export{t as __pageData,n as default};
